mapper.select:
SELECT , c.name AS course_name, NULL AS read_flag FROM edu_notice n LEFT JOIN edu_course c ON c.id = n.course_id AND c.deleted = 0 WHERE n.deleted = 0
AND n.course_id = #{courseId}
AND n.title LIKE CONCAT('%', #{title}, '%')
AND n.status = #{status}
AND n.type = #{type}
AND n.course_id IN (SELECT id FROM edu_course WHERE teacher_id = #{teacherId} AND deleted = 0)
ORDER BY n.publish_time DESC, n.id DESC

SELECT , c.name AS course_name, CASE WHEN r.id IS NOT NULL THEN 1 ELSE 0 END AS read_flag FROM edu_notice n LEFT JOIN edu_course c ON c.id = n.course_id AND c.deleted = 0 LEFT JOIN edu_notice_read r ON r.notice_id = n.id AND r.student_id = #{studentId} WHERE n.deleted = 0 AND n.status = 1 AND n.course_id IN ( SELECT DISTINCT sgc.course_id FROM edu_student_group_course sgc JOIN edu_student_group_member sgm ON sgm.group_id = sgc.group_id WHERE sgm.student_id = #{studentId} )
AND n.type = #{type}
ORDER BY n.publish_time DESC, n.id DESC

SELECT COUNT(*)
FROM edu_notice n
WHERE n.deleted = 0
  AND n.status = 1
  AND n.course_id IN (
      SELECT DISTINCT sgc.course_id
      FROM edu_student_group_course sgc
      JOIN edu_student_group_member sgm ON sgm.group_id = sgc.group_id
      WHERE sgm.student_id = #{studentId}
  )
  AND NOT EXISTS (
      SELECT 1 FROM edu_notice_read r WHERE r.notice_id = n.id AND r.student_id = #{studentId}
  )
